parameters.jsCode:
const groups = {};

for (const item of items) {

  // Defensive Check
  if (!item.json.output?.property?.address) {
    continue;
  }

  const address = item.json.output.property.address;

  if (!groups[address]) {
    groups[address] = {
      address,
      landlord: item.json.output.landlord,
      units: []
    };
  }

  groups[address].units.push(item.json.output);
}

return Object.values(groups).map(g => ({ json: g }));

